import { motion } from "framer-motion";
import { Search, Sparkles, Video, Plane } from "lucide-react";

const STEPS = [
    {
        n: "01",
        icon: Search,
        title: "Browse the atelier",
        body: "Discover hand-picked Indian ethnic collections — bridal, festive and everyday — sourced from India's most loved boutiques.",
    },
    {
        n: "02",
        icon: Sparkles,
        title: "Curate & request",
        body: "Save the silhouettes that speak to you and book a private live consultation at a time that suits your timezone.",
    },
    {
        n: "03",
        icon: Video,
        title: "Shop live with India",
        body: "Walk through the store on video. See the fall of the fabric, the shimmer of the zari, ask anything — in real time.",
    },
    {
        n: "04",
        icon: Plane,
        title: "Delivered worldwide",
        body: "We pack, document and ship your piece in luxury, trusted packaging — door to door, anywhere on earth.",
    },
];

export default function HowItWorks() {
    return (
        <section id="how" data-testid="how-it-works" className="relative py-24 md:py-36 px-6 md:px-12 lg:px-20">
            <div className="max-w-7xl mx-auto">
                <div className="grid grid-cols-12 gap-8 md:gap-12 mb-16 md:mb-24">
                    <div className="col-span-12 md:col-span-5">
                        <p className="text-[11px] uppercase tracking-[0.32em] text-maroon mb-5">
                            The experience
                        </p>
                        <h2 className="font-serif text-4xl sm:text-5xl md:text-6xl text-espresso tracking-tightest leading-[1.05]">
                            Four steps to a wardrobe that{" "}
                            <span className="serif-italic">arrives like art.</span>
                        </h2>
                    </div>
                    <div className="col-span-12 md:col-span-6 md:col-start-7 flex items-end">
                        <p className="text-base md:text-lg text-stone leading-relaxed">
                            We've reimagined the journey from <em className="serif-italic">scroll</em> to{" "}
                            <em className="serif-italic">silhouette</em>. Every piece is touched by a
                            human — never by an algorithm alone.
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 md:gap-8">
                    {STEPS.map((s, i) => (
                        <motion.div
                            key={s.n}
                            initial={{ opacity: 0, y: 30 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true, amount: 0.3 }}
                            transition={{ duration: 0.8, delay: i * 0.08, ease: [0.22, 0.61, 0.36, 1] }}
                            data-testid={`step-card-${i + 1}`}
                            className="group relative bg-white/60 backdrop-blur-md border border-line-soft rounded-[2rem] p-8 md:p-10 hover:shadow-2xl transition-all duration-700 hover:-translate-y-1"
                        >
                            <div className="flex items-start justify-between mb-10">
                                <span className="font-serif text-5xl text-maroon/30 leading-none">{s.n}</span>
                                <div className="w-12 h-12 rounded-full glass flex items-center justify-center text-maroon group-hover:bg-maroon group-hover:text-ivory transition-all duration-500">
                                    <s.icon className="w-5 h-5" strokeWidth={1.4} />
                                </div>
                            </div>
                            <h3 className="font-serif text-2xl md:text-[1.7rem] text-espresso mb-3 leading-snug">
                                {s.title}
                            </h3>
                            <p className="text-sm md:text-[0.95rem] text-stone leading-relaxed">
                                {s.body}
                            </p>
                            <div className="hairline mt-8" />
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
}
